var e=[{id:`L2_1`,type:`subtitle`,speaker:null,text:{KOREA:`인류 통합 방위군 제7 방위선, 거점 기지`,JPN:`人類統合防衛軍第7防衛線、拠点基地`,ENG:`Base, United Humankind Defense Force's 7th Defense Line`,TWN:`人類共同保衛軍 第七防線基地`,THA:`ฐานทัพ แนวป้องกันที่ 7 ของกองกำลังป้องกันมนุษยชาติ`,VTN:`Căn cứ, Phòng Tuyến thứ 7 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất`,SCN:`人类综合防卫军第7防线，据点基地`,DEU:`Basis, 7. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit`,FRA:`Base de la 7e ligne de défense des Forces de défense unies de l'humanité`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`안 돼. 이럴 수는 없어, 이럴 수는.`,JPN:`そんな、嘘。こんなの嘘よ。`,ENG:`No. This can't be happening.`,TWN:`不，不可能，怎麼會……`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`인류가 힘겹게 쌓아 올린 제7 방위선이 이렇게나 허무하게.`,JPN:`人類が苦闘の末に築き上げた第7防衛線が、こんなにも虚しく。`,ENG:`The 7th Defense Line that we worked so hard to build can't go down like this.`,TWN:`人類費盡力氣建造的第七防線怎麼會如此不堪一擊…`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`모두, 모두 나 때문이야.`,JPN:`全部、全部私のせいだ。`,ENG:`It's... It's all my fault.`,TWN:`全部……都是因為我。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`시영 씨, 사이버캣 그리고 다른 대원들 모두 나 때문에.`,JPN:`シノンさん、サイバーキャット、そして他の隊員のみんなが私のせいで。`,ENG:`It's my fault for what happened to Shiyoung, Cyber Cat, and all the other troops.`,TWN:`時雨，賽博貓還有其他隊員們，都是因為我才…`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`흑, 흐흑……!`,JPN:`う……うう……っ！`,ENG:`*Sniffle* Hnnggg...!`,TWN:`嗚，嗚嗚……！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`대령님, 이제 저는 어떻게 해야……!`,JPN:`大佐、私はこれからどうすれば……！`,ENG:`Colonel, what am I supposed to do...?`,TWN:`上校，我現在該怎麼辦……！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`이 소리는……?`,JPN:`今の音は……？`,ENG:`What's that sound...?`,TWN:`有聲音……？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`누군가 있어! 아직 누군가 살릴 수 있을 지도 몰라!`,JPN:`誰かいる！　まだ誰か助けられる人がいるのかもしれないわ！`,ENG:`Someone's here! There's still someone I can save!`,TWN:`有人！也許還有人活著！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`피터, 피터 대원! 정신 차리세요, 피터 대원!`,JPN:`ピーター、ピーター隊員！　しっかり、ピーター隊員！`,ENG:`Peter, Peter! Wake up, Peter!`,TWN:`彼得，彼得隊員！醒醒，彼得！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`소…… 령님?`,JPN:`しょ、小……佐？`,ENG:`Maj... or?`,TWN:`少……校？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`그래요, 저예요! 안심하세요! 제가 왔으니 살 수 있어요!`,JPN:`はい、私です！　もう安心してください！　私が助けに来ましたから！`,ENG:`Yes, it's me! Don't worry! I'm here to save you!`,TWN:`對，是我！放心吧！我來了，你會沒事的！`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`저, 저를…….`,JPN:`ぼ、僕を……`,ENG:`P-please...`,TWN:`我，我……`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_C`,text:{KOREA:`주, 죽여…… 주세요. 소령…… 님.`,JPN:`こ、殺して……ください。少佐……`,ENG:`K-kill me, M-Major...`,TWN:`請，請殺了……我。少校……。`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`예?`,JPN:`え？`,ENG:`What?`,TWN:`什麼？`},stage:{bg:`COUNTERSIDE_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};